settings.custom_liquid:
{%- assign tomorrow_at_midnight = 'now' | date: '%s' | plus: 86400 -%}

<div class="shipping-banner">
  <span class="pulse-dot"></span>
  <p class="shipping-text">
    Order now, ships by: <strong>{{ tomorrow_at_midnight | date: '%A, %b. %d' }}</strong>
  </p>
</div>

<style>
  .shipping-banner {
    display: none;
    align-items: center;
    justify-content: center;
    background-color: #F1FFEF; /* Sage green background */
    color: #000000;
    padding: 8px 20px;
    border-radius: 8px; /* Fully rounded capsule shape */
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    max-width: 100%;
    margin: 10px auto;
  }

  .shipping-text {
    margin: 0;
    font-size: 14px;
    letter-spacing: 0.2px;
  }

  .shipping-text strong {
    color: #084D3A; /* Darker green for the date */
    font-weight: 700;
  }

  .pulse-dot {
    height: 12px;
    width: 12px;
    background-color: #73D55F;
    border-radius: 50%;
    display: inline-block;
    margin-right: 12px;
    box-shadow: 0 0 0 0 rgba(102, 224, 94, 0.7);
    animation: pulse 2s infinite;
  }

  @keyframes pulse {
    0% {
      transform: scale(0.95);
      box-shadow: 0 0 0 0 rgba(102, 224, 94, 0.7);
    }
    70% {
      transform: scale(1);
      box-shadow: 0 0 0 6px rgba(102, 224, 94, 0);
    }
    100% {
      transform: scale(0.95);
      box-shadow: 0 0 0 0 rgba(102, 224, 94, 0);
    }
  }
</style>

{% comment %}
  Christmas Gift Wrapping Banner
  Usage: {% render 'christmas-banner' %}
{% endcomment %}

<style>
  .christmas-banner {
    border-radius: 10px;
    background: #B91C2E;
    padding: 10px;
    margin: 40px 0;
    display: flex;
    align-items: center;
    gap: 30px;
    max-width: 100%;
  }

  .christmas-banner__image-wrapper {
    flex-shrink: 0;
  }

  .christmas-banner__image {
    width: 80px;
    height: 80px;
    object-fit: cover;
    border-radius: 8px;
  }

  .christmas-banner__content {
    flex: 1;
    color: white;
  }

  .christmas-banner__title {
    font-size: 18px;
    font-weight: 700;
    line-height: 1.1;
    margin: 0 0 8px 0;
    color: white;
  }

  .christmas-banner__subtitle {
    font-size: 14px;
    font-weight: 300;
    line-height: 1.2;
    margin: 0;
    color: white;
  }

  @media (max-width: 768px) {
    .christmas-banner {
      padding: 20px 25px;
      gap: 20px;
    }

    .christmas-banner__image {
      width: 80px;
      height: 80px;
    }

    .christmas-banner__title {
      font-size: 18px;
    }

    .christmas-banner__subtitle {
      font-size: 12px;
    }
  }

  @media (max-width: 480px) {
    .christmas-banner {
      padding: 15px 15px;
      gap: 15px;
    }

    .christmas-banner__image {
      width: 70px;
      height: 70px;
    }

    .christmas-banner__title {
      font-size: 18px;
    }

    .christmas-banner__subtitle {
      font-size: 12px;
    }
  }
</style>

<div class="christmas-banner">
  <div class="christmas-banner__image-wrapper">
    <img 
      src="https://cdn.shopify.com/s/files/1/0798/4028/0923/files/Gemini_Generated_Image_jwexemjwexemjwex.png?v=1765376774 
      alt="Christmas gift wrapping"
      class="christmas-banner__image"
      loading="lazy"
    >
  </div>
  <div class="christmas-banner__content">
    <h2 class="christmas-banner__title">Order now to receive before Christmas!</h2>
    <p class="christmas-banner__subtitle">Order by the end of today for guaranteed Christmas delivery.</p>
  </div>
</div>
